app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots").strip("/")
SCREENSHOT_WIDTH = int(os.getenv("SCREENSHOT_WIDTH", "1280"))
SCREENSHOT_HEIGHT = int(os.getenv("SCREENSHOT_HEIGHT", "720"))
THUMBNAIL_WIDTH = int(os.getenv("THUMBNAIL_WIDTH", "400"))
PAGE_LOAD_TIMEOUT = int(os.getenv("PAGE_LOAD_TIMEOUT", "30"))
WAIT_AFTER_LOAD = float(os.getenv("WAIT_AFTER_LOAD", "2.0"))
CACHE_CONTROL = os.getenv("CACHE_CONTROL", "public, max-age=31536000, immutable")
ALLOWED_SCHEMES = {"http", "https"}

s3 = boto3.client("s3", region_name=AWS_REGION)


def validate_url(url: str) -> str:
    if not url:
        raise ValueError("Missing url")
    url = url.strip()
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError("Invalid url scheme")
    if not parsed.netloc:
        raise ValueError("Invalid url")
    return url


def build_s3_key(url: str, variant: str = "thumbnail") -> str:
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{variant}/{digest}.png" if S3_PREFIX else f"{variant}/{digest}.png"


def s3_url_exists(key: str) -> bool:
    if not S3_BUCKET:
        return False
    try:
        s3.head_object(Bucket=S3_BUCKET, Key=key)
        return True
    except botocore.exceptions.ClientError as e:
        code = e.response.get("Error", {}).get("Code", "")
        if code in ("404", "NoSuchKey", "NotFound"):
            return False
        return False


def download_s3_object(key: str) -> Optional[bytes]:
    if not S3_BUCKET:
        return None
    try:
        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        return obj["Body"].read()
    except Exception:
        return None


def upload_to_s3(key: str, data: bytes, content_type: str = "image/png") -> None:
    if not S3_BUCKET:
        return
    s3.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=data,
        ContentType=content_type,
        CacheControl=CACHE_CONTROL,
        ACL="private",
    )


def get_webdriver():
    if webdriver is None:
        raise RuntimeError("selenium is not available")
    options = ChromeOptions()
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument(f"--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--disable-extensions")
    options.add_argument("--single-process")
    options.add_argument("--no-zygote")
    options.add_argument("--remote-debugging-port=9222")
    driver = webdriver.Chrome(options=options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    return driver


def capture_screenshot(url: str) -> bytes:
    driver = get_webdriver()
    try:
        driver.get(url)
        time.sleep(WAIT_AFTER_LOAD)
        try:
            driver.execute_script("window.scrollTo(0, 0);")
        except Exception:
            pass
        png = driver.get_screenshot_as_png()
        return png
    finally:
        try:
            driver.quit()
        except Exception:
            pass


def create_thumbnail(image_bytes: bytes) -> bytes:
    try:
        from PIL import Image
    except Exception:
        return image_bytes
    with Image.open(io.BytesIO(image_bytes)) as img:
        img = img.convert("RGB")
        w, h = img.size
        if w <= THUMBNAIL_WIDTH:
            out = io.BytesIO()
            img.save(out, format="PNG")
            return out.getvalue()
        ratio = THUMBNAIL_WIDTH / float(w)
        new_h = max(1, int(h * ratio))
        img = img.resize((THUMBNAIL_WIDTH, new_h), Image.LANCZOS)
        out = io.BytesIO()
        img.save(out, format="PNG")
        return out.getvalue()


