@app.route("/screenshot", methods=["GET", "POST"])
def screenshot():
    payload = request.get_json(silent=True) or {}
    url = request.args.get("url") or payload.get("url")
    try:
        url = validate_url(url)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

    variant = request.args.get("variant", "thumbnail")
    key = build_s3_key(url, variant=variant)

    if s3_url_exists(key):
        data = download_s3_object(key)
        if data:
            return send_file(io.BytesIO(data), mimetype="image/png", as_attachment=False)

    try:
        image_bytes = capture_screenshot(url)
        if variant == "thumbnail":
            image_bytes = create_thumbnail(image_bytes)
        upload_to_s3(key, image_bytes)
        return send_file(io.BytesIO(image_bytes), mimetype="image/png", as_attachment=False)
    except Exception as e:
        return jsonify({"error": "screenshot_failed", "details": str(e)}), 500


@app.route("/preview", methods=["GET", "POST"])
def preview():
    payload = request.get_json(silent=True) or {}
    url = request.args.get("url") or payload.get("url")
    try:
        url = validate_url(url)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

    key = build_s3_key(url, variant="thumbnail")
    s3_uri = f"s3://{S3_BUCKET}/{key}" if S3_BUCKET else None
    public_url = None
    if S3_BUCKET:
        public_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"

    if s3_url_exists(key):
        return jsonify({"url": url, "thumbnail": public_url, "s3_key": key, "cached": True})

    try:
        image_bytes = capture_screenshot(url)
        image_bytes = create_thumbnail(image_bytes)
        upload_to_s3(key, image_bytes)
        return jsonify({"url": url, "thumbnail": public_url, "s3_key": key, "cached": False})
    except Exception as e:
        return jsonify({"error": "preview_failed", "details": str(e)}), 500


